var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"맡겨 둔 기억을 되찾으러 왔다.","JPN":"預けた記憶を取り戻しに来た。","ENG":"I'm here to reclaim my memory.","TWN":"我來找回我託付的記憶。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그럼 처음부터 그렇게 얘기하면 됐잖아.","JPN":"じゃあ、最初からそう言いなさいよ。","ENG":"You could've led with that.","TWN":"那你一開始就應該這麼說。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"전사란 족속들은 이래서 상종하면 안 돼. 무식하게 힘부터 쓰고 본다니까.","JPN":"だから戦士は嫌いなんだよ。力づくで解決しようとするから。","ENG":"This is why I don't hang out with warriors. They just go straight to violence.","TWN":"你們這些戰士就知道動用武力，真不應該和你們有什麼往來。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"……그래도 제법이네.","JPN":"……でも、なかなかやるね。","ENG":"...Not bad, though.","TWN":"……不過非常不錯喔。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"네 이름과 기억을 되찾으러 왔다는 건, 클리포트게임을 무사히 넘겼단 거겠지?","JPN":"あなたの名前と記憶を取り戻しに来たってことは、クリフォトゲームを無事乗り越えたってことでしょ？","ENG":"If you're here to reclaim your name and memory, that must mean the Qliphoth Game is safely over.","TWN":"你來找回記憶，說明你順利度過了逆卡巴拉遊戲？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그 과정에서 <color=#ffd34c>녀석</color>이 멋대로 일을 추진한 건 썩 마음에 들진 않지만…","JPN":"その途中で<color=#ffd34c>奴</color>が勝手に仕事を進めたのはあまり気に入らないが……","ENG":"I'm not happy about the fact that <color=#ffd34c>he</color> went ahead with this during that process, but...","TWN":"雖然在這過程中，那<color=#ffd34c>傢伙</color>總是自作主張……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"성과가 좋았다는 건 인정해야겠지.","JPN":"成果があったという点は認めるべきだろう。","ENG":"I'll have to admit, the outcome was pretty good.","TWN":"但不得不承認取得了不錯的成果。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"헹, 맨날 마음에 안 든다면서 걘 왜 한 번도 안 때리냐? 응? 나랑 다르게 가진 목숨이 하나뿐이라서?","JPN":"ふんっ、いつも気に入らないって言ってる割には一度も殴らなかったじゃない。私と違って、命が一つだけだから？","ENG":"Heh. You always say you don't like him, but why don't you ever hit him? Huh? Just because he only has one life, unlike me?","TWN":"哼，你既然那麼討厭他，為什麼從來都不會打他呢？嗯？是因為他只有一條命嗎？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그게 아니면 실은 너 걔 좋아한다거나…","JPN":"それとも、実はあなた、あいつのことが好きだったり……","ENG":"Or is it because you like him–","TWN":"或者說你其實心裡是喜歡他的……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"야야- 야야야야야야야-! 그렇게 당기면 꼬리 끊어져! 끊어진다고…!","JPN":"ちょちょーちょっとちょっとちょっとちょっとー！　引っ張らないで尻尾とれちゃう！　とれるって……！","ENG":"Ow! Owwww oww oww! Stop tugging on my tail! It's going to fall off! It's falling off...!","TWN":"喂喂——呀啊啊啊啊啊——！尾巴會斷的！快放手……！"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"헛소리 끝났으면 본론으로 넘어가.","JPN":"戯言は済んだか？　本題に入れ。","ENG":"Get to the point.","TWN":"廢話說完了吧，我們來談正事。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"조… 좋아.","JPN":"わ……わかったよ。","ENG":"F-fine.","TWN":"好……好吧。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"날 여기서 꺼내 줘. 답답해 죽을 지경이었거든.","JPN":"私をここから出して。息苦しくて死にそうだったの。","ENG":"Get me out of here. I'm dying of boredom.","TWN":"把我弄出去吧，我快悶死了。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"내 요구는?","JPN":"私の要求は？","ENG":"What about my demands?","TWN":"我的要求呢？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"일단 땅에 발부터 딛고나서 생각해 볼게.","JPN":"地上に着いたら考えるよ。","ENG":"I'll think about it after I set foot on earth.","TWN":"等我出去之後再考慮。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"거절하지. 네 녀석이 또 무슨 장난질을 하며 사라질지도 모르니까.","JPN":"断る。お前がまたどんな悪戯をして消えるかわからないからな。","ENG":"I refuse. You might play some trick and disappear again.","TWN":"我拒絕。誰知道你又會搞什麼把戲。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"부탁 안 들어주면 네 가장 부끄러운 과거를 이 녀석들한테 말해버릴 거야.","JPN":"お願いを聞いてくれなかったら、あなたの一番恥ずかしい過去をこいつらに話しちゃうよ？","ENG":"I'm going to tell them your most embarrassing past if you don't meet my demands.","TWN":"如果你不幫我忙，我就把你最丟人的過去告訴這些人。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"오, 뭔데 뭔데? 나 궁금해!","JPN":"え、なになに？　知りたい！","ENG":"Oh, what is it? I wanna know!","TWN":"喔，是什麼？好想知道！"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"궁금할 것도 없다. 녀석이 하는 말은 대부분 거짓과 기만이니까.","JPN":"その必要はない。奴の言葉はほとんどが嘘と欺瞞だからな。","ENG":"Nothing to be curious about. Most things that come out of her mouth are lies and deceit.","TWN":"沒什麼可好奇的，她說的話大部分都是騙人的。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"뭐- 맛보기로 말해주자면, 지금은 마냥 시크한 척하는 쟤도 옛날엔…","JPN":"まあ～ちょっとだけ話すと、今はクールに振舞ってるこの人も昔は……","ENG":"Well, I'll give you a taste. She acts so tough right now, but she used to–","TWN":"好，那我就稍微透露一下。這傢伙現在雖然裝得一副不可一世，但其實以前……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"으갸갸갸갹!! 내 팔!!","JPN":"いたたたたっ！！　腕が！！","ENG":"Aghhh!! My arm!!","TWN":"啊啊啊啊！！我的手臂！！"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_BONE_CRACK"},{"id":"L41_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"까불지 말고 약속이나 지켜.","JPN":"調子に乗るな。約束を守れ。","ENG":"Be quiet and keep your word.","TWN":"別胡鬧了，快遵守約定。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"이건 반칙이야! 힘 차이 뻔히 알면서 팔을 비트는 게 어딨어!","JPN":"こんなの反則だよ！　力の差をわかってるくせに、腕を捻るなんて！","ENG":"You're cheating! You can't twist my arm knowing you're much stronger than me!","TWN":"這是犯規！明明知道我力氣比你弱還扭我的手臂！"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하루이틀 죽어보는 것도 아니면서 엄살만 늘었군.","JPN":"何回も死んだくせに、大げさな女だ。","ENG":"You've died more than enough times to be whining about this.","TWN":"你已經死了那麼多次了，還是這麼喜歡裝弱。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그래도 최근엔 제법 살아있었거든!","JPN":"これでも最近は結構生きてたんだよ！","ENG":"I was pretty alive recently, okay?!","TWN":"這次我活了蠻長的時間！"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"으으… 이번엔 팔 제대로 빠졌네.","JPN":"うう……脱臼してる。","ENG":"Ugh... My arm's dislocated.","TWN":"唉……手臂骨折了。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"제가 도와드릴게요. 이런 건 경험이 좀 있거든요.","JPN":"僕が診ましょう。こういうの、経験があるんですよ。","ENG":"Let me help you. I have some experience.","TWN":"讓我來幫忙吧，我在這方面有些經驗。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"앗, 진짜? 살살 부탁해.","JPN":"あ、本当に？　お手柔らかにお願いね。","ENG":"Oh, really? Be gentle, please.","TWN":"喔，真的嗎？拜託輕一點。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"으읏…","JPN":"ううっ……","ENG":"Ugh...","TWN":"唉……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"오, 이제 안 아파!","JPN":"おっ、もう痛くない！","ENG":"Oh, it doesn't hurt anymore!","TWN":"喔，不痛了！"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L5_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"솜씨 좋네, 헤이븐? 역시 의사 집안이라 그런가?","JPN":"やるね、ヘイブン。やっぱり医者の家系だからかな？","ENG":"Not bad, Haven. I guess you do come from a family of doctors.","TWN":"真厲害，天堂？不愧是出身醫生世家！"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"예? 저를 아시나요?","JPN":"え？　僕のこと、知ってるんですか？","ENG":"Pardon? Do you know me?","TWN":"嗯？你認識我嗎？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"알다마다. 네 못난 누이가 널 속여먹고 있다는 것도 알지.","JPN":"当たり前でしょ。あなたの悪いお姉さんがあなたを騙してることも知ってるよ。","ENG":"Of course I do. I also know that your mean sister has been lying to you.","TWN":"當然了。我還知道你愚蠢的姊姊騙了你。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"네가 여기 왔다는 건… 전개상 그 착한 심성 때문에 식구들 죄를 전부 독박을 쓰고 왔다는 뜻이겠네, 안 그래?","JPN":"あなたがここに来たってことは……その優しい性格のせいで家族の罪を一人で背負ったってところかな。違う？","ENG":"If you're here... that must mean that your kind heart led you to take on all the responsibility for your family's crimes.","TWN":"你來到這裡說明……心地善良的你獨自承擔了一家人的所有罪過，對不對？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그걸 당신이 어떻게?","JPN":"どうしてそんなことまで？","ENG":"How did you know that?","TWN":"你怎麼知道？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"경고했을 텐데? 녀석이 하는 말에 너무 귀기울이지 말라고.","JPN":"警告したはずだ。こいつの話にあまり耳を傾けるなと。","ENG":"I warned you. Don't take her too seriously.","TWN":"我警告過你，別輕信她的話。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"틈이 보이면 널 이용해먹으려 들 거다.","JPN":"隙を見せると、利用されるぞ。","ENG":"She's going to use you when she sees an opening.","TWN":"她只要一旦發現機會就會利用你。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"아… 알겠습니다.","JPN":"あ……わかりました。","ENG":"Ah... Okay.","TWN":"啊……知道了。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"아직 아무것도 안 했는데 너무한 거 아냐?","JPN":"まだ何もしてないのに、ひどくない？","ENG":"That's a little harsh when I haven't even done anything.","TWN":"你好過分，我明明什麼都沒做？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그나저나, 발키리의 앙숙이어야 할 엑자일러까지 끼어 있고… 특이한 조합이구만.","JPN":"それより、ヴァルキリーとライバル関係のエグザイラーまでいるなんて……変わった組み合わせだね。","ENG":"By the way, what an odd group of people... including an Exile, which Valkyries especially hate.","TWN":"話說女武神竟然會和死對頭流放者在一起……好奇怪的組合。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"하아- 내가 슬럼프가 오지만 않았어도 괜찮은 각본이 떠올랐을 텐데.","JPN":"はあ～スランプじゃなかったらいい脚本が浮かんだだろうな～。","ENG":"*Sigh.* I would've come up with a decent script if I wasn't going through writer's block.","TWN":"唉——如果我沒有陷入低谷，一定能寫出一個很出色的劇本。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"당신 말하는 걸 보니 작가 같은 거야?","JPN":"あんた、作家なの？","ENG":"Are you a writer or something, then?","TWN":"這麼說你是位作家？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"뭐, 설명하자면 여러 방식이 있겠지만 요즘 녀석들이 알아듣게 하자면…","JPN":"まあ、色んな説明方法があるけど、最近の若者がわかるように言うと……","ENG":"Well, there are many ways to explain this, but to make it easy for the new generation...","TWN":"嗯，我有很多種方式介紹自己，簡單來講……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"유혹의 함교라고 들어 봤으려나?","JPN":"誘惑の艦橋って聞いたことあるかな？","ENG":"Have you heard of The Bridge of Seduction?","TWN":"你聽說過誘惑的艦橋嗎？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"앗, 그 드라마?! 당연히 알지!","JPN":"あっ、あのドラマ！？　もちろん知ってるよ！","ENG":"Oh, the soap opera?! Of course, I do!","TWN":"啊，那部連續劇嗎？！我當然知道！"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"설마 당신이 그걸 쓴 거야?! 보조작가 같은 건가?","JPN":"まさか、あんたがそれ書いたの？！　補助作家とか？","ENG":"Did you write it yourself?! Or like, an assistant writer?","TWN":"難道那部劇是你寫的？！你是助理作家還是什麼？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"내가 혼자 집필한 거야. 시즌1 한정이지만.","JPN":"私一人で執筆したの。シーズン1限定だけど。","ENG":"I wrote it all alone. Just the first season, though.","TWN":"第一季是我一個人完成的。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"제작사 녀석들, 인기 좀 오르니까 자꾸 자극적으로 해달라고 졸라대서 말이야.","JPN":"製作会社の奴ら、人気が出るから内容をもっと刺激的にしろってうるさくてね。","ENG":"The production company kept begging me to make it more dramatic after it gained popularity.","TWN":"戲紅了之後，製作公司的人總是要求我寫出更灑狗血的劇情。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"리프래시 좀 하겠다고 둘러대면서 빠져나왔지.","JPN":"ちょっとリフレッシュしたいって言い訳して逃げたの。","ENG":"I told them I needed a break, and got out of the whole thing.","TWN":"於是我就以休養為藉口停筆了。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"흠결 없는 작품으로 평가받는 건 시즌1이 유일하긴 하죠.","JPN":"欠点のない作品として評価されてるのはシーズン1が唯一ですね。","ENG":"It's true that season 1 is the only season that's considered flawless.","TWN":"第一季確實是唯一被認為是無懈可擊的一季。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그런데… 그런 걸 쓰던 분이 어쩌다가 슈퍼맥스급 감옥에 갇히게 된 건가요?","JPN":"でも……そんなすごい作品を書いた人が、どうしてスーパーマックス級の監獄に閉じ込められているんですか？","ENG":"But... How did someone like you end up in a maximum-security prison?","TWN":"那麼……這麼厲害的人為什麼會被關進這可怕的監獄裡呢？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"나처럼 오래 살다 보면 원하지 않아도 별의별 일에 휘말리기 마련이거든.","JPN":"私みたいに長生きしてると、望んでなくても色んなことに巻き込まれるんだよ。","ENG":"When you live as long as I have, you end up getting tangled in different incidents, whether you like it or not.","TWN":"你活得久了就會像我一樣被捲進各種各樣的事情中。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"관리국의 표적이 된 순간 저항도 못하고 붙잡힌 거다. 녀석은 어린애와의 팔씨름에서 질 정도로 힘이 형편없으니까.","JPN":"管理局の標的になった瞬間、抵抗できずに捕まったのだ。こいつは子どもとの腕相撲に負けるほど、非力だからな。","ENG":"She was caught as soon as she became the Administration's target. She's so weak that she'd lose in arm wrestling with a child.","TWN":"她被管理局盯上的那一刻就被逮捕了。她的力氣弱到和一個小孩子比腕力也比不過。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"우리 사이에 한 번쯤 내 편도 좀 들어주라.","JPN":"ちょっと、一度くらい私の肩も持ってよ。","ENG":"It won't hurt to take my side once in a while.","TWN":"你能不能偶爾也替我說句好話。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"잡담은 이쯤하지.","JPN":"雑談はここまでにしよう。","ENG":"Enough chitchat.","TWN":"閒話少說。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"시간 끌지 말고 내 기억이나 가져와.","JPN":"さっさと、私の記憶を持って来い。","ENG":"Stop stalling and bring me my memory.","TWN":"別再拖了，快把記憶還給我。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"끄응… 그거 말이지.","JPN":"うーん……あれね。","ENG":"Ngh... About that.","TWN":"嗯……這個嘛。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"사실 나한테 없어.","JPN":"実は私、持ってないの。","ENG":"I don't have it.","TWN":"其實不在我這裡。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭐라고? 너…!","JPN":"なんだと？　お前……！","ENG":"What? You–","TWN":"什麼？你……！"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"PRIME_NPC_PRISON_MECH","text":{"KOREA":"보이드존에 침입한 죄수들을 발견했다.","JPN":"ボイドゾーンに侵入した囚人を発見。","ENG":"Found the prisoners who trespassed the Void Zone.","TWN":"發現了闖入虛無區的囚犯。"},"stage":{"bg":"PRISON_SPACE","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L4_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"쯧.","JPN":"チッ。","ENG":"Tch.","TWN":"嘖。"},"stage":{"bg":"PRISON_SPACE","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L5_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"고철 만드는 것도 지겨워지는데, 볼일은 슬슬 끝내지?","JPN":"鉄くず作りももう飽きたんだけど、そろそろ用事は終わらせたらどう？","ENG":"I'm getting tired of making scrap metal out of them. Can you end this quickly?","TWN":"我已經開始厭倦製造這些廢鐵了。動作稍微快點吧？"},"stage":{"bg":"PRISON_SPACE","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"PRIME_NPC_PRISON_MECH","text":{"KOREA":"보안 프로토콜… 규격외 레벨.","JPN":"保安プロトコル……規格外のレベル。","ENG":"Security protocol... Unable to assess level.","TWN":"安全協議……不符合違規級別。"},"stage":{"bg":"PRISON_SPACE","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L8_1","type":"dialog","speaker":"PRIME_NPC_PRISON_MECH","text":{"KOREA":"아케론의 전 보안 시스템은 보이드존의 죄수가 탈출하는 것을 막아라.","JPN":"アケロンの全保安システムは、ボイドゾーンの囚人が脱出することを阻止しろ。","ENG":"All security systems in Acheron are to stop the Void Zone prisoner from escaping.","TWN":"黃泉的全部安全系統，馬上阻止虛無區的囚犯逃離。"},"stage":{"bg":"PRISON_SPACE","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"패러독스.","JPN":"パラドックス。","ENG":"Paradox.","TWN":"悖論。"},"stage":{"bg":"PRISON_SPACE","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"넌 나중에 얘기하자.","JPN":"後で話そう。","ENG":"We'll talk later.","TWN":"以後再找你算帳。"},"stage":{"bg":"PRISON_SPACE","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"윽…","JPN":"うっ……","ENG":"Ngh...","TWN":"呃……"},"stage":{"bg":"PRISON_SPACE","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};